package com.example.myapplication.domain.workout

import com.example.myapplication.data.settings.UserPreferencesRepository
import com.example.myapplication.viewmodels.BodyHomeUiState
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import com.example.myapplication.data.UserPreferences
import java.time.LocalDate

class GetBodyMetricsUseCase(private val workoutRepo: WorkoutRepository, private val settingsRepo: UserPreferencesRepository) {
    fun invoke(email: String): Flow<BodyHomeUiState> = flow {
        // Emit loading state initially
        emit(BodyHomeUiState(isLoading = true))

        var state = BodyHomeUiState(isLoading = false)

        try {
            // Firestore Sync: Preberi osvežene podatke in posodobi lokalno bazo
            val stats = UserPreferences.getWorkoutStats(email)
            if (stats != null) {
                val streak = stats["streak_days"] as? Int ?: 0
                val total = stats["total_workouts_completed"] as? Int ?: 0
                val weeklyDone = stats["weekly_done"] as? Int ?: 0
                val weeklyTarget = stats["weekly_target"] as? Int ?: 3
                val planDay = stats["plan_day"] as? Int ?: 1
                val lastEpoch = stats["last_workout_epoch"] as? Long ?: 0L

                val isDoneToday = if (lastEpoch == 0L) false else LocalDate.ofEpochDay(lastEpoch) == LocalDate.now()

                // Sync with local repository
                settingsRepo.updateWorkoutStats(
                    completedDay = planDay,
                    timestamp = if (lastEpoch > 0) lastEpoch * 86400000L else 0L
                )

                state = state.copy(
                    streakDays = streak,
                    weeklyDone = weeklyDone,
                    weeklyTarget = weeklyTarget,
                    planDay = planDay,
                    totalWorkoutsCompleted = total,
                    isWorkoutDoneToday = isDoneToday
                )
            } else {
                // Če ni v Firestore (prvi zagon brez oblaka), preberi začasno to kar imamo preden prepiše vse na null
                // Ker je ta koda tu fallback, uporabimo zasilne vrednosti dokler se ne uredi
                val isDoneLocally = settingsRepo.isWorkoutDoneToday()
                state = state.copy(
                    planDay = settingsRepo.getPlanDay(),
                    weeklyTarget = settingsRepo.getWeeklyTarget(),
                    isWorkoutDoneToday = isDoneLocally
                )
            }
        } catch (e: Exception) {
            state = state.copy(errorMessage = e.message)
        }

        emit(state)
    }
}

package com.example.myapplication.domain.workout

import com.example.myapplication.data.PlanResult

class SwapPlanDaysUseCase {
    fun invoke(currentPlan: PlanResult, dayA: Int, dayB: Int): Result<PlanResult> {
        return try {
            val weekA = (dayA - 1) / 7
            val weekB = (dayB - 1) / 7

            if (weekA != weekB) {
                return Result.failure(Exception("Cross-week swap not allowed: $dayA <-> $dayB"))
            }

            val allDays = currentPlan.weeks.flatMap { it.days }.toMutableList()
            val iA = allDays.indexOfFirst { it.dayNumber == dayA }
            val iB = allDays.indexOfFirst { it.dayNumber == dayB }

            if (iA >= 0 && iB >= 0) {
                val rA = allDays[iA].isRestDay
                val fA = allDays[iA].focusLabel
                val rB = allDays[iB].isRestDay
                val fB = allDays[iB].focusLabel
                allDays[iA] = allDays[iA].copy(isRestDay = rB, focusLabel = fB)
                allDays[iB] = allDays[iB].copy(isRestDay = rA, focusLabel = fA)
            }

            val updatedWeeks = currentPlan.weeks.map { week ->
                week.copy(days = allDays.filter { (it.dayNumber - 1) / 7 == week.weekNumber - 1 })
            }
            val updatedPlan = currentPlan.copy(weeks = updatedWeeks)
            Result.success(updatedPlan)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.myapplication.domain.workout

import com.example.myapplication.domain.gamification.ManageGamificationUseCase
import com.example.myapplication.domain.gamification.WorkoutCompletionResult
import com.example.myapplication.data.settings.UserPreferencesRepository
import kotlinx.datetime.Clock
import kotlinx.datetime.TimeZone
import kotlinx.datetime.toLocalDateTime

class UpdateBodyMetricsUseCase(
    private val workoutRepo: WorkoutRepository,
    private val gamificationUseCase: ManageGamificationUseCase,
    private val settingsRepo: UserPreferencesRepository
) {
    suspend operator fun invoke(
        email: String,
        totalKcal: Int,
        totalTimeMin: Double,
        exercisesCount: Int,
        planDay: Int,
        isExtra: Boolean,
        exerciseResults: List<Map<String, Any>>
    ): Result<WorkoutCompletionResult?> {
        return try {
            if (isExtra) {
                val workoutDoc = hashMapOf(
                    "date" to com.google.firebase.firestore.FieldValue.serverTimestamp(),
                    "type" to "extra",
                    "totalKcal" to totalKcal,
                    "totalTimeMin" to totalTimeMin,
                    "exercisesCount" to exercisesCount,
                    "planDay" to planDay,
                    "exercises" to exerciseResults
                )
                workoutRepo.saveWorkoutSession(email, workoutDoc)
                // Legacy SharedPreferences extra prep update
                Result.success(null)
            } else {
                val tz = TimeZone.currentSystemDefault()
                val hour = Clock.System.now().toLocalDateTime(tz).hour
                val res = gamificationUseCase.recordWorkoutCompletion(totalKcal.toDouble(), hour)

                val workoutDoc = hashMapOf(
                    "date" to com.google.firebase.firestore.FieldValue.serverTimestamp(),
                    "type" to "regular",
                    "totalKcal" to totalKcal,
                    "totalTimeMin" to totalTimeMin,
                    "exercisesCount" to exercisesCount,
                    "planDay" to planDay,
                    "exercises" to exerciseResults
                )
                workoutRepo.saveWorkoutSession(email, workoutDoc)
                gamificationUseCase.completeWorkoutSession(100) // basic XP tracking
                Result.success(res)
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

